   Ejemplo de SplFileObject::fscanf


<?php
$file = new SplFileObject("usuarios.txt");
while ($usuarioinfo = $file->fscanf("%s %s %s")) {
   list ($nombre, $profesion, $codigopais) = $usuarioinfo;
   // Operar con  $name $profession $countrycode
}
?>


